import{_ as e,o as t,c as r,ai as o}from"./chunks/framework.CzqNhXfh.js";const h=JSON.parse('{"title":"23.11-12月纪录与总结","description":"","frontmatter":{"layout":"doc"},"headers":[],"relativePath":"essays/articles/article-003.md","filePath":"essays/articles/article-003.md","lastUpdated":1776825361000}'),s={name:"essays/articles/article-003.md"};function l(i,a,p,c,_,n){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="_23-11-12月纪录与总结" tabindex="-1">23.11-12月纪录与总结 <a class="header-anchor" href="#_23-11-12月纪录与总结" aria-label="Permalink to &quot;23.11-12月纪录与总结&quot;">​</a></h1><blockquote><p>子昱 闲谈之余 2023年12月30日 13:01 湖北</p></blockquote><h2 id="_1-关于她" tabindex="-1">1.关于她 <a class="header-anchor" href="#_1-关于她" aria-label="Permalink to &quot;1.关于她&quot;">​</a></h2><p>谈起这两个月，最大的变化无疑是她。除了同学之外，她多了一层身份——我的女朋友。直至现在，我仍觉得很不可思议。略显笨拙的我在当天晚上甚至不知道该如何开口，便有些强取豪夺地牵紧了她的手。现在想来，站在她的角度，我像是一个没有表明来意的客人进入了她的房间。后悔莫及...</p><p>我们俩在一起直至今天，正好两个月，时间如冬日的寒风一样从耳边飕飕驶过，不给人反应的机会。刚在一起的时候，我仿佛是第一次认识她，此前所有的经历变成了虚幻，我变得小心翼翼，那个自以为了解你的我消失得无影无踪。熟悉又陌生的感觉恰如是。刚在一起的时候，我们发生过几次不愉快,彼时的感觉痛苦万分。但随着时间流逝，我们相处得越来越和谐。</p><p>很长一段时间里，我对她的爱意绵绵不止。尽管几乎每天我们都能相见，一起上下课，但学业为重，我们接触很少。也许正是因为这种常常近距离的爱而不得，使得我每时每刻都想与她在一起。脑海中一有闲暇空余，无不是她的身影。夜幕深深中，闭上双眼，&quot;我好想你，你在哪呢...&quot;。</p><p>我希望这种感觉永远持续：心里有值得挂念的人，生活的底色将多姿多彩。我不知道我们能在一起走多久，但从相处的这一段时间看来，我很喜欢你，喜欢你的一切。两个人在一起最重要的是陪伴，不仅是开心的陪伴，更重要的是失意落寞时的陪伴。最近几天，由于选导师选方向的事情在自我烦恼和焦虑，但一和你聊天，哪怕只是一些日常的分享，我心里的烦忧顿时消散了一大半，治愈的话语置于心间，一切其实也没那么可怕，慢慢来就好了。</p><p>真心希望我们能一直走下去，你有我在，我有你在。</p><h2 id="_2-关于学业与生活" tabindex="-1">2.关于学业与生活 <a class="header-anchor" href="#_2-关于学业与生活" aria-label="Permalink to &quot;2.关于学业与生活&quot;">​</a></h2><p>这两个月的整体节奏明显放缓了，我花费了更多的心力去思考我的未来。读硕 读博？去哪里读？选导师？选方向？去企业？当老师？工作 定居？一大堆的问题接踵而来，纷纷占据我的脑海。诚然，一时间无法将这些问题都想明白，它们太复杂了。也许再过两三年，随着年龄和阅历的增大，我的想法也会随之而变。但关于接下来的深造问题，我是必须要慎重抉择的。找了很多学长学姐还有老师聊天，想得到一些启发，摸索着未来的道路.......</p><p>和她在一起之后，最启发我的一点是阅读习惯。我自以为，我是喜欢看书的，但不喜欢将阅读这样宝贵的事情放到忙碌的工作学习之余，草草了事。在假期的一大段一大段的时间中，放肆地享受阅读体验，才是我最喜欢的。但现在看来，其实并不适用于我。在学校的日子，每天晚上回到寝室，其实也有一两个小时的阅读时间，我大可以两耳一塞，将自己埋在阅读世界中，不管他人。此时读读散文，读读杂文都挺好。在假期，并不见得我会将大把大把的时间留给阅读，还有更多有吸引力的其他事情。况且，本科以后的日子里，不再有如此之长的寒暑假了，且过且珍惜。</p><p>阅读是让人保持思考的必要途径之一。倘若每天都仅仅是忙碌于工作学习，用短视频度过碎片时间，人会囿于自己的小世界中，不知不觉的在固定的观念下原地踏步，思想</p>',12)])])}const u=e(s,[["render",l]]);export{h as __pageData,u as default};
